export function script(input) {
  const issues = Array.isArray(input.issues) ? input.issues : [];
  const errors = Array.isArray(input.errors) ? input.errors : [];
  const supabaseUrl = typeof input.supabaseUrl === 'string' ? input.supabaseUrl.trim() : '';
  const authorizationNotes = typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null;
  const severityRank = { critical: 5, high: 4, medium: 3, low: 2, info: 1, none: 0, unknown: 0 };
  const normalizeSeverity = (value) => String(value || 'medium').toLowerCase();
  const rankFor = (value) => severityRank[normalizeSeverity(value)] ?? 3;
  function firstText(...values) {
    for (const value of values) {
      if (typeof value === 'string' && value.trim().length > 0) return value.trim();
    }
    return null;
  }
  function issueRecord(issue) {
    const record = typeof issue === 'object' && issue !== null ? issue : { raw: issue };
    const checkId = firstText(record.check_id, record.checkId, record.id, record.title) || 'unknown-check';
    const resource = firstText(record.resource, record.table, record.bucket, record.schema) || null;
    const severity = normalizeSeverity(record.severity);
    const category = firstText(record.category, record.check_type, record.type) || null;
    const message = firstText(record.message, record.description, record.detail, record.remediation) || null;
    const priorityBand = rankFor(severity) >= 4 ? 'immediate' : rankFor(severity) >= 3 ? 'high-review' : rankFor(severity) >= 2 ? 'watchlist' : 'backlog';
    return { checkId, resource, severity, category, message, priorityBand, priorityScore: rankFor(severity) * 100 };
  }
  const priorityFindings = issues.map(issueRecord).sort((a, b) => b.priorityScore - a.priorityScore || a.checkId.localeCompare(b.checkId)).slice(0, 100);
  const countsBySeverity = priorityFindings.reduce((acc, finding) => {
    acc[finding.severity] = (acc[finding.severity] || 0) + 1;
    return acc;
  }, {});
  const highestSeverity = priorityFindings.reduce((current, finding) => rankFor(finding.severity) > rankFor(current) ? finding.severity : current, 'none');
  const scoreValue = Number.isFinite(Number(input.score)) ? Number(input.score) : null;
  const summary = typeof input.summary === 'object' && input.summary !== null ? input.summary : {};
  const assetKey = input.projectRef || supabaseUrl;
  return {
    report: {
      summary: {
        supabaseUrl,
        projectRef: input.projectRef || null,
        securityScore: scoreValue,
        issueCount: issues.length,
        actionableFindings: priorityFindings.length,
        highestSeverity,
        countsBySeverity,
        scannerSummary: summary,
        scannerErrors: errors
      },
      authorizationNotes,
      priorityFindings,
      analyticsResults: priorityFindings.slice(0, 100).map((finding) => ({
        scanner: 'supabase-scanner',
        severity: finding.severity,
        finding_hash: [finding.checkId, assetKey, finding.resource || ''].join(':'),
        asset_key: assetKey,
        check_id: finding.checkId,
        resource: finding.resource
      })),
      nextSteps: [
        'Confirm the Supabase project is explicitly authorized before reporting',
        'Prioritize critical and high findings related to RLS, storage bucket policies, and exposed API keys',
        'Wire a Service Role key on the scanner node for deeper API and storage checks when authorized',
        'Re-run after remediation to validate score improvements'
      ]
    }
  };
}
